cd /home/banzo
# Backup
if [ -f vm_inventory_updater.py ]; then
    cp vm_inventory_updater.py vm_inventory_updater.py.backup.$(date +%Y%m%d_%H%M%S)
    echo 'Backup created'
fi

# Write new file using base64 to avoid command line length issues
cat > /tmp/vm_script_base64.txt << 'ENDBASE64'

ENDBASE64

# Decode and write
python3 << 'ENDPYTHON'
import binascii
with open('/tmp/vm_script_base64.txt', 'r') as f:
    hex_content = f.read().strip()
content = bytes.fromhex(hex_content).decode('utf-8')
with open('/home/banzo/vm_inventory_updater.py', 'w') as f:
    f.write(content)
print('File written')
ENDPYTHON

# Verify
if [ -f /home/banzo/vm_inventory_updater.py ]; then
    echo 'SUCCESS: File deployed'
    ls -lh /home/banzo/vm_inventory_updater.py
    if grep -q 'FIX: Only use fallback if API actually failed' /home/banzo/vm_inventory_updater.py; then
        echo '[OK] San Patricio fix found'
    else
        echo '[ERROR] San Patricio fix NOT found'
    fi
    if grep -q 'LARGE DISCREPANCY DETECTED' /home/banzo/vm_inventory_updater.py; then
        echo '[OK] Validation fix found'
    else
        echo '[ERROR] Validation fix NOT found'
    fi
else
    echo 'ERROR: File not created'
    exit 1
fi
